diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 394dfca262e1..4887eae8d023 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3881,6 +3881,7 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     }
   }

+
   // select(C, Z, binop(select(C, X, Y), W)) -> select(C, Z, binop(Y, W))
   BinaryOperator *FalseBO;
   if (match(FalseVal, m_OneUse(m_BinOp(FalseBO))) && !FalseBO->isIntDivRem()) {
@@ -3900,6 +3901,27 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     }
   }

+  // select C2, (select C1, A, B), (select C1, B, A) --> select (xor C1, C2), B, A
+  // This handles the case where two selects with the same condition but swapped
+  // values are selected by another condition.
+  auto *TrueSI = dyn_cast<SelectInst>(TrueVal);
+  auto *FalseSI = dyn_cast<SelectInst>(FalseVal);
+  if (TrueSI && FalseSI && TrueSI->hasOneUse() && FalseSI->hasOneUse()) {
+    Value *InnerCond = TrueSI->getCondition();
+    if (InnerCond == FalseSI->getCondition()) {
+      Value *TrueValTrue = TrueSI->getTrueValue();
+      Value *TrueValFalse = TrueSI->getFalseValue();
+      Value *FalseValTrue = FalseSI->getTrueValue();
+      Value *FalseValFalse = FalseSI->getFalseValue();
+      // Check if the true/false values are swapped between the two selects.
+      if (TrueValTrue == FalseValFalse && TrueValFalse == FalseValTrue) {
+        Value *XorCond = Builder.CreateXor(InnerCond, CondVal);
+        Value *NewSel = Builder.CreateSelect(XorCond, TrueValFalse, TrueValTrue);
+        return replaceInstUsesWith(SI, NewSel);
+      }
+    }
+  }
+
   Value *NotCond;
   if (match(CondVal, m_Not(m_Value(NotCond))) &&
       !InstCombiner::shouldAvoidAbsorbingNotIntoSelect(SI)) {
@@ -4081,3 +4103,4 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {

   return nullptr;
 }
+

